import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';
import initialDataYaml from './变量初始化_zod.yaml?raw';
import YAML from 'yaml';


import { z } from 'zod';
export const Schema = z.object({
  世界: z.object({
    日期: z.string(),
    时间: z.string(),
    星期: z.string(),
    天气: z.string()
  }).strict(),

  玩家: z.object({
    位置: z.string()
  }).strict(),

  角色: z.record(
    z.string().describe('角色名'),
    z.object({
      位置: z.string(),
      状态: z.string(),
      心情: z.string(),
      好感度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      警戒度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      身体敏感度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      意识值: z.coerce.number().transform(v => _.clamp(v, 0, 100))
    }).strict()
  ).prefault({}),

  李强: z.object({
    位置: z.string(),
    警戒度: z.coerce.number().transform(v => _.clamp(v, 0, 100))
  }).strict(),

  摄像头: z.record(
    z.string().describe('摄像头名'),
    z.object({
      安装位置: z.string(),
      暴露度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      摄像内容: z.string()
    }).strict()
  ).prefault({}),

  设备: z.record(
    z.string().describe('设备名'),
    z.object({
      安装位置: z.string(),
      状态: z.string(),
      作用: z.string()
    }).strict()
  ).prefault({}),

  仓库: z.record(
    z.string().describe('物品名'),
    z.object({
      数量: z.coerce.number().transform(v => Math.max(0, v)),
      作用: z.string()
    }).strict()
  ).prefault({})
}).strict();

$(() => {
  /* 注册 MVU Schema */
  registerMvuSchema(Schema);

  /* 自动初始化变量 */
  (async () => {
    try {
      /* 解析 YAML 数据 */
      const initialData = YAML.parse(initialDataYaml);

      /* 等待 MVU 系统初始化 */
      await waitGlobalInitialized('Mvu');

      /* 监听聊天切换事件，在新聊天中自动初始化 */
      eventOn(tavern_events.CHAT_CHANGED, async () => {
        try {
          const chat_messages = getChatMessages();
          if (chat_messages.length === 0) {
            console.info('[窥视者日常] 无聊天消息，跳过变量初始化');
            return;
          }

          const last_message_id = chat_messages[chat_messages.length - 1].id;
          const current_data = Mvu.getMvuData({ type: 'message', message_id: last_message_id });

          /* 检查是否已经初始化 */
          if (current_data && Object.keys(current_data).length > 0) {
            console.info('[窥视者日常] 变量已存在，跳过初始化');
            return;
          }

          /* 使用 Schema 验证并初始化数据 */
          const validated_data = Schema.parse(initialData);
          Mvu.replaceMvuData(validated_data, { type: 'message', message_id: last_message_id });
          console.info('[窥视者日常] 变量初始化成功');
        } catch (error) {
          console.error('[窥视者日常] 变量初始化失败:', error);
        }
      });

      /* 首次加载时也尝试初始化 */
      const chat_messages = getChatMessages();
      if (chat_messages.length > 0) {
        const last_message_id = chat_messages[chat_messages.length - 1].id;
        const current_data = Mvu.getMvuData({ type: 'message', message_id: last_message_id });

        if (!current_data || Object.keys(current_data).length === 0) {
          const validated_data = Schema.parse(initialData);
          Mvu.replaceMvuData(validated_data, { type: 'message', message_id: last_message_id });
          console.info('[窥视者日常] 变量初始化成功');
        } else {
          console.info('[窥视者日常] 变量已存在，跳过初始化');
        }
      }
    } catch (error) {
      console.error('[窥视者日常] 变量初始化失败:', error);
    }
  })();
});
